"""send_image_to_claude.py"""
import anthropic
from image_utils import load_and_resize, to_base64

client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env

# --- Method 1: local file as base64 ---
raw = load_and_resize("invoice.jpg", max_long_edge=1024)
b64 = to_base64(raw)

response_base64 = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=512,
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/jpeg",
                        "data": b64,
                    },
                },
                {
                    "type": "text",
                    "text": "What is the total amount due shown on this invoice? Reply with just the number.",
                },
            ],
        }
    ],
)
print("Base64 result:", response_base64.content[0].text)
print("Image tokens used:", response_base64.usage.input_tokens)

# --- Method 2: public URL (no base64 encoding needed) ---
response_url = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=256,
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "url",
                        "url": "https://example.com/product.jpg",
                    },
                },
                {
                    "type": "text",
                    "text": "Describe this product in one sentence suitable for an e-commerce listing.",
                },
            ],
        }
    ],
)
print("URL result:", response_url.content[0].text)

"""comparison_agent.py — compare before/after product images and report differences."""
from pathlib import Path
from typing import Literal

import anthropic
from pydantic import BaseModel

from image_utils import load_and_resize, to_base64


class ComparisonResult(BaseModel):
    verdict: Literal["identical", "minor_differences", "significant_differences"]
    differences: list[str]  # human-readable list of changes
    confidence: float        # 0.0 – 1.0


def compare_images(
    before_path: str | Path,
    after_path: str | Path,
    context: str = "product quality control",
) -> ComparisonResult:
    """
    Send two images to Claude in a single request and ask it to identify
    visual differences. Claude can hold multiple images in one message.
    """
    client = anthropic.Anthropic()

    before_bytes = load_and_resize(before_path, max_long_edge=1024)
    after_bytes  = load_and_resize(after_path,  max_long_edge=1024)

    schema = ComparisonResult.model_json_schema()

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        system=(
            f"You are a visual QA assistant specialising in {context}. "
            "Compare the two images (labelled BEFORE and AFTER) and return ONLY a JSON "
            f"object matching this schema: {schema}. No prose outside JSON."
        ),
        messages=[
            {
                "role": "user",
                "content": [
                    {"type": "text", "text": "BEFORE image:"},
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/jpeg",
                            "data": to_base64(before_bytes),
                        },
                    },
                    {"type": "text", "text": "AFTER image:"},
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/jpeg",
                            "data": to_base64(after_bytes),
                        },
                    },
                    {"type": "text", "text": "Identify all visual differences between BEFORE and AFTER."},
                ],
            }
        ],
    )

    return ComparisonResult.model_validate_json(response.content[0].text.strip())


# --- usage ---
if __name__ == "__main__":
    result = compare_images("product_before.jpg", "product_after.jpg")
    print(f"Verdict: {result.verdict} (confidence: {result.confidence:.0%})")
    for diff in result.differences:
        print(f"  • {diff}")
